function twoLists(matches) {
    const loss_count = new Map();
    const participants = new Set();

    for (const [winner, loser] of matches) {
        loss_count.set(loser, (loss_count.get(loser) || 0) + 1);
        participants.add(winner);
        participants.add(loser);
    }

    const no_losses = new Set();
    const one_loss = new Set();

    for (const participant of participants) {
        const count = loss_count.get(participant) || 0;
        if (count === 0) {
            no_losses.add(participant);
        } else if (count === 1) {
            one_loss.add(participant);
        }
    }

    return [no_losses, one_loss];
}
```

